const fs = require('fs');
const path = require('path');

// asar 是 zip-based 的自定义格式，尝试用 asar 模块或手动解析
// 先检查是否有 asar 可用
try {
    const asar = require('asar');
    const list = asar.listArchive(path.join('D:\\windsurf_assistant\\resources', 'app.asar'));
    // 只取前几层目录结构
    const topDirs = new Set();
    const pkgFiles = [];
    list.forEach(f => {
        const parts = f.split('/');
        if (parts.length <= 2) topDirs.add(f);
        if (f === 'package.json' || f.startsWith('package.json/')) {
            pkgFiles.push(f);
        }
    });
    console.log('=== Top-level structure (first 50) ===');
    [...topDirs].slice(0, 50).forEach(f => console.log(f));
    console.log('\n=== Package files ===');
    pkgFiles.forEach(f => console.log(f));
} catch(e) {
    console.log('asar module not available, trying manual approach...');
    console.log(e.message);
}

